import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { ResponsiveChartContainer, LinePlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface UsageData {
  current: number;
  trend: number[];
}

interface SystemData {
  cpuUsage: UsageData;
  ramUsage: UsageData;
  diskUsage: UsageData;
  processCount: number;
}

export default function Widget() {
  const systemData = response.data as SystemData;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#1F2937' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ color: '#F59E0B' }}>
              System Monitor
            </Typography>
            <Typography variant="body2" color="text.secondary" sx={{ mb: 1 }}>
              CPU Usage: {systemData.cpuUsage.current}%
            </Typography>
            <Typography variant="body2" color="text.secondary" sx={{ mb: 1 }}>
              RAM Usage: {systemData.ramUsage.current}%
            </Typography>
            <Typography variant="body2" color="text.secondary" sx={{ mb: 1 }}>
              Disk Usage: {systemData.diskUsage.current}%
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Processes: {systemData.processCount}
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 150 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'line',
                  data: systemData.cpuUsage.trend,
                  color: '#F59E0B',
                  label: 'CPU',
                },
              ]}
              xAxis={[
                {
                  scaleType: 'linear',
                  data: systemData.cpuUsage.trend.map((_, i) => i),
                  id: 'time',
                },
              ]}
              yAxis={[{ id: 'usage' }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <LinePlot />
              </g>
              <ChartsXAxis
                axisId="time"
                tickLabelStyle={{ fontSize: 10, fill: '#9CA3AF' }}
              />
              <ChartsYAxis
                axisId="usage"
                tickLabelStyle={{ fontSize: 10, fill: '#9CA3AF' }}
              />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
